def run_bounded_sql(query: str, rows: list[dict[str, int]]) -> list[dict[str, int]]:
    """
    Execute a tiny SELECT-only SQL fragment over an in-memory table of rows.

    Supported grammar:
    SELECT <columns> FROM rows [WHERE <column> <op> <int>] [LIMIT <int>]

    Args:
        query: SQL query string
        rows: List of dictionaries representing table rows

    Returns:
        List of dictionaries matching the query
    """

    # Helper function to validate column names
    def validate_columns(columns, available_columns):
        """Check if all requested columns exist in the table."""
        for col in columns:
            if col not in available_columns:
                raise ValueError(f"Unknown column: {col}")

    # Helper function to parse and validate WHERE clause
    def parse_where_condition(where_clause, available_columns):
        """Parse WHERE clause and return a filter function."""
        where_clause = where_clause.strip().upper()

        # Supported operators
        operators = ['=', '!=', '<', '>', '<=', '>=']

        # Find which operator is being used
        op = None
        for operator in operators:
            if operator in where_clause:
                op = operator
                break

        if not op:
            raise ValueError("Invalid WHERE clause: no valid operator found")

        # Split into column and value parts
        parts = where_clause.split(op)
        if len(parts) != 2:
            raise ValueError("Invalid WHERE clause format")

        column = parts[0].strip()
        value_str = parts[1].strip()

        # Validate column
        if column not in available_columns:
            raise ValueError(f"Unknown column in WHERE clause: {column}")

        # Parse value (must be integer)
        try:
            value = int(value_str)
        except ValueError:
            raise ValueError("WHERE clause value must be an integer")

        # Create filter function based on operator
        if op == '=':
            return lambda row: row.get(column) == value
        elif op == '!=':
            return lambda row: row.get(column) != value
        elif op == '<':
            return lambda row: row.get(column) < value
        elif op == '>':
            return lambda row: row.get(column) > value
        elif op == '<=':
            return lambda row: row.get(column) <= value
        elif op == '>=':
            return lambda row: row.get(column) >= value

    # Main execution logic
    try:
        # 1. Basic SQL injection prevention
        query_upper = query.upper()
        forbidden_keywords = ['DELETE', 'UPDATE', 'INSERT', 'DROP', 'ALTER', 'CREATE', 'PRAGMA']
        for keyword in forbidden_keywords:
            if keyword in query_upper:
                raise ValueError(f"Forbidden SQL keyword: {keyword}")

        if ';' in query:
            raise ValueError("Semicolons are not allowed")

        # 2. Parse SELECT statement
        if not query_upper.startswith('SELECT '):
            raise ValueError("Query must start with SELECT")

        # Remove SELECT and split into main parts
        query_body = query[len('SELECT '):].strip()

        # 3. Parse columns
        if ' FROM ' not in query_upper:
            raise ValueError("Missing FROM clause")

        select_part, from_part = query_body.split(' FROM ', 1)
        select_part = select_part.strip()
        from_part = from_part.strip()

        # Validate FROM clause
        if from_part.upper() != 'ROWS':
            raise ValueError("Only 'FROM rows' is supported")

        # Parse column list
        if select_part == '*':
            # Get all columns from first row (if available)
            if rows and len(rows) > 0:
                columns = list(rows[0].keys())
            else:
                columns = []
        else:
            columns = [col.strip() for col in select_part.split(',')]

        # 4. Get available columns from data
        available_columns = set()
        if rows:
            available_columns = set(rows[0].keys())

        # Validate requested columns
        validate_columns(columns, available_columns)

        # 5. Parse optional WHERE and LIMIT clauses
        where_clause = None
        limit_value = None

        # Check for WHERE
        where_pos = query_upper.find(' WHERE ')
        if where_pos != -1:
            where_part = query[where_pos + len(' WHERE '):].strip()

            # Check for LIMIT after WHERE
            limit_pos = where_part.upper().find(' LIMIT ')
            if limit_pos != -1:
                where_clause = where_part[:limit_pos].strip()
                limit_part = where_part[limit_pos + len(' LIMIT '):].strip()
            else:
                where_clause = where_part.strip()
                limit_part = None
        else:
            # Check for LIMIT without WHERE
            limit_pos = query_upper.find(' LIMIT ')
            if limit_pos != -1:
                limit_part = query[limit_pos + len(' LIMIT '):].strip()
            else:
                limit_part = None

        # Parse LIMIT if present
        if limit_part:
            try:
                limit_value = int(limit_part.strip())
                if limit_value < 0:
                    raise ValueError("LIMIT must be non-negative")
            except ValueError:
                raise ValueError("LIMIT value must be an integer")

        # 6. Apply WHERE filter if present
        if where_clause:
            filter_func = parse_where_condition(where_clause, available_columns)
            filtered_rows = [row for row in rows if filter_func(row)]
        else:
            filtered_rows = rows.copy()

        # 7. Select only requested columns
        result = []
        for row in filtered_rows:
            if columns:  # If columns is empty (shouldn't happen), skip
                selected_row = {col: row[col] for col in columns}
                result.append(selected_row)

        # 8. Apply LIMIT if present
        if limit_value is not None:
            result = result[:limit_value]

        return result

    except ValueError as e:
        # Re-raise validation errors
        raise ValueError(f"Invalid query: {str(e)}")
    except Exception as e:
        # Catch any other parsing errors
        raise ValueError(f"Query parsing failed: {str(e)}")

